// In a shared utility, e.g. packages/channels-extra/src/channel-utils.ts:
import type { Logger } from '@guiiai/logg'
import type { IncomingMessage, MessageHandler } from './types.js'

export function dispatchToHandlers(
  handlers: MessageHandler[],
  message: IncomingMessage,
  logger: { withError: (err: Error) => { error: (msg: string) => void } },
): void {
  for (const handler of handlers) {
    try {
      const result = handler(message)
      if (result instanceof Promise) {
        result.catch(err => logger.withError(err as Error).error('async message handler error'))
      }
    } catch (err) {
      logger.withError(err as Error).error('sync message handler error')
    }
  }
}

// Each channel then calls:
dispatchToHandlers(this.messageHandlers, incomingMessage, logger)

WHY: Eliminates 33 lines of duplicated dispatch logic. A bug fix to handler invocation (e.g., adding proper void handling) would otherwise require 3 coordinated edits.

