// Option A: Abstract base class
abstract class BaseChannel implements Channel {
  abstract readonly platform: ChannelPlatform
  protected _status: ChannelStatus = 'disconnected'
  protected messageHandlers: MessageHandler[] = []
  private statusHandlers: StatusChangeHandler[] = []

  get status(): ChannelStatus { return this._status }

  protected setStatus(status: ChannelStatus): void {
    this._status = status
    for (const handler of this.statusHandlers) {
      try { handler(status) }
      catch (err) { /* logged */ }
    }
  }

  onStatusChange(handler: StatusChangeHandler): () => void { /* shared */ }
  onMessage(handler: MessageHandler): () => void { /* shared */ }
}

// Option B: Composition - createHandlerRegistry() utility
// Returns { addHandler, removeHandler, dispatch } to avoid inheritance.

WHY: ~105 lines of identical boilerplate consolidated. Changes to handler management (e.g., adding priority ordering) would require editing only one location.

