// In BaseChannel (if using Option A from finding 002):
protected async connectWithGuard(setup: () => Promise<void>, depsDescription: string): Promise<void> {
  this.setStatus('connecting')
  if (!this.deps) {
    this.setStatus('error')
    throw new Error(`${this.platform} channel requires ${depsDescription}`)
  }
  try {
    await setup()
    this.setStatus('connected')
  } catch (error) {
    this.setStatus('error')
    throw new Error(`${this.platform} connect failed`, { cause: error })
  }
}

// Each subclass:
async connect(): Promise<void> {
  await this.connectWithGuard(async () => {
    this.client = this.deps!.createClient()
    // ...channel-specific setup
  }, 'createClient and createWsClient')
}

WHY: Removes the repeated status-management boilerplate from connect/disconnect, letting each channel focus only on its specific setup/teardown logic.

